import { useRef, useState } from "react"
import { a11y, page, render, renderHook } from "#test/browser"
import { FocusLock } from "./focus-lock"

describe("<FocusLock />", () => {
  test("sets `displayName` correctly", () => {
    expect(FocusLock.name).toBe("FocusLock")
  })

  test("passes a11y checks", async () => {
    await a11y(
      <FocusLock>
        <button>Focused Button</button>
      </FocusLock>,
    )
  })

  test("correctly focuses on elements within the lock", async () => {
    await render(
      <>
        <button>Not Focused Button</button>
        <FocusLock>
          <button>Focused Button</button>
        </FocusLock>
      </>,
    )

    const notFocusedBtn = page.getByRole("button", {
      name: "Not Focused Button",
      exact: true,
    })
    const focusedBtn = page.getByRole("button", {
      name: "Focused Button",
      exact: true,
    })

    focusedBtn.element().focus()
    await expect.element(focusedBtn).toHaveFocus()

    notFocusedBtn.element().focus()
    await expect.element(focusedBtn).toHaveFocus()
  })

  test("correctly focuses on the button with a reference when initialized", async () => {
    const { result } = await renderHook(() => useRef(null))

    await render(
      <FocusLock initialFocusRef={result.current}>
        <button>Not Focused Button</button>
        <button ref={result.current}>Focused Button</button>
      </FocusLock>,
    )

    const focusedBtn = page.getByRole("button", {
      name: "Focused Button",
      exact: true,
    })
    await expect.element(focusedBtn).toHaveFocus()
  })

  test("correctly focuses on contentRef when no focusable elements exist", async () => {
    const { result } = await renderHook(() => useRef(null))

    await render(
      <FocusLock contentRef={result.current}>
        {/* eslint-disable-next-line jsx-a11y/no-noninteractive-tabindex */}
        <div ref={result.current} tabIndex={0}>
          No focusable elements here
        </div>
      </FocusLock>,
    )

    const contentDiv = page.getByText("No focusable elements here")
    await expect.element(contentDiv).toHaveFocus()
  })

  test("correctly focuses on the finalFocusRef when the FocusLock is unmounted", async () => {
    const TestComponent = () => {
      const [isMounted, setIsMounted] = useState(true)
      const outsideButtonRef = useRef<HTMLButtonElement>(null)

      return (
        <div>
          <button ref={outsideButtonRef}>Outside Button</button>

          {isMounted ? (
            <FocusLock finalFocusRef={outsideButtonRef}>
              <button>Focus Lock Button</button>
            </FocusLock>
          ) : null}

          <button onClick={() => setIsMounted(false)}>
            Unmount FocusLock Button
          </button>
        </div>
      )
    }

    const { user } = await render(<TestComponent />)

    const focusLockButton = page.getByRole("button", {
      name: "Focus Lock Button",
    })
    const outsideButton = page.getByRole("button", { name: "Outside Button" })
    const unmountButton = page.getByRole("button", {
      name: "Unmount FocusLock Button",
    })

    // Focus on a button inside the FocusLock
    focusLockButton.element().focus()
    await expect.element(focusLockButton).toHaveFocus()

    // Unmount the FocusLock
    await user.click(unmountButton)

    // Check that focus returns to the outside button
    await expect.element(outsideButton).toHaveFocus()
  })
})

"use client"

import type { FC, PropsWithChildren, RefObject } from "react"
import { useCallback } from "react"
import ReactFocusLock from "react-focus-lock"
import { getFocusableElements, interopDefault } from "@yamada-ui/react"

const InternalFocusLock = interopDefault(ReactFocusLock)

export interface FocusLockProps extends PropsWithChildren {
  /**
   * If `true`, the first focusable element within the `children` will auto-focused once `FocusLock` mounts.
   *
   * @default false
   */
  autoFocus?: boolean
  /**
   * The `ref` of the wrapper for which the focus-lock wraps.
   */
  contentRef?: RefObject<HTMLElement | null>
  /**
   * If `true`, focus trapping will be disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * `ref` of the element to return focus to when `FocusLock` unmounts.
   */
  finalFocusRef?: RefObject<HTMLElement | null>
  /**
   * `ref` of the element to receive focus initially.
   */
  initialFocusRef?: RefObject<HTMLElement | null>
  /**
   * Enables aggressive focus capturing within iframes.
   * - If `true`: keep focus in the lock, no matter where lock is active.
   * - If `false`:  allows focus to move outside of iframe.
   *
   * @default false
   */
  lockFocusAcrossFrames?: boolean
  /**
   * If `true`, disables text selections inside, and outside focus lock.
   *
   * @default false
   */
  persistentFocus?: boolean
  /**
   * If `true`, focus will be restored to the element that triggered the `FocusLock` once it unmounts.
   *
   * @default false
   */
  restoreFocus?: boolean
}

/**
 * `FocusLock` is a component that improves accessibility by restricting focus within elements such as modals and dialogs, and locking the focus within that range.
 *
 * @see https://yamada-ui.com/docs/components/focus-lock
 */
export const FocusLock: FC<FocusLockProps> = ({
  autoFocus,
  children,
  contentRef,
  disabled,
  finalFocusRef,
  initialFocusRef,
  lockFocusAcrossFrames,
  persistentFocus,
  restoreFocus,
}) => {
  const returnFocus = restoreFocus && !finalFocusRef

  const onActivation = useCallback(() => {
    if (initialFocusRef?.current) {
      initialFocusRef.current.focus()
    } else if (contentRef?.current) {
      const focusables = getFocusableElements(contentRef.current)

      if (focusables.length === 0)
        requestAnimationFrame(() => {
          contentRef.current?.focus()
        })
    }
  }, [initialFocusRef, contentRef])

  const onDeactivation = useCallback(() => {
    finalFocusRef?.current?.focus()
  }, [finalFocusRef])

  return (
    <InternalFocusLock
      autoFocus={autoFocus}
      crossFrame={lockFocusAcrossFrames}
      disabled={disabled}
      persistentFocus={persistentFocus}
      returnFocus={returnFocus}
      onActivation={onActivation}
      onDeactivation={onDeactivation}
    >
      {children}
    </InternalFocusLock>
  )
}
